/**
 * 通用「对话式写作 Agent」引擎
 *
 * 把写卡助手（card-agent.ts）那套「多轮澄清 → 生成草稿 → 微调/重做 + 流式 + 会话草稿持久化」
 * 抽象成一个由「领域配置（WritingDomain）」驱动的通用引擎，让开场白 / NPC / 世界书条目等
 * 其它写作工具都能复用同一套对话体验，而不用各自重写一遍对话 UI。
 *
 * 设计要点：
 * - 不依赖模型 function-calling（公益站模型参差不齐），用「固定阶段 + 结构化输出」编排，稳。
 * - 复用现有 requestToolsAiText / streamToolsAiText（自动兼容直连 API / 酒馆 API / 流式）。
 * - 领域差异全部收敛到 WritingDomain 配置里；引擎与 UI 组件保持通用。
 */

import {
    extractJsonFromText,
    requestToolsAiText,
    streamToolsAiText,
    type ToolsAiSettings,
} from '../components/tools/toolsAiService';
import { readCurrentCharacterCard } from './card-agent';
import { collectWorldbookText } from './worldbook-reader';

/** 领域产物类型，决定 UI 上出现哪些「写入」按钮、草稿如何解析 */
export type WritingOutputKind = 'greeting' | 'npc' | 'worldbook';

/** 一个写作领域的配置 */
export interface WritingDomain {
  /** 唯一 id（用于草稿持久化隔离） */
  id: string;
  /** UI 标题 */
  title: string;
  /** 主题色（hex） */
  accent: string;
  /** UI 顶部说明 */
  intro: string;
  /** 输入框 placeholder */
  placeholder: string;
  /** 空对话时的提示 */
  emptyHint: string;
  /** system 人设描述（“你是…”） */
  persona: string;
  /** 澄清阶段：开始正式生成前必须问清的关键信息 */
  clarifyGoal: string;
  /** 生成草稿阶段：如何产出这次的成品 */
  draftInstruction: string;
  /** 产物类型 */
  output: WritingOutputKind;
  /** 是否把当前角色卡作为背景带给 AI */
  useCharContext?: boolean;
  /** 是否把当前生效的全部世界书作为背景带给 AI */
  useWorldbookContext?: boolean;
}

/** 对话消息 */
export interface WritingMessage {
  role: 'user' | 'assistant';
  content: string;
  /** 该条消息携带的产物（草稿/结构化数据），供 UI 渲染操作按钮 */
  artifact?: WritingArtifact;
}

export interface WritingArtifact {
  type: 'draft';
  /** 给用户看的正文 */
  text: string;
  /** 结构化数据（worldbook / npc 解析出的条目等） */
  data?: any;
}

export interface WritingAgentState {
  stage: 'clarify' | 'draft' | 'done';
  messages: WritingMessage[];
  /** 已确认的设定要点（澄清阶段逐步累积） */
  facts: string[];
  /** 最近一次草稿文本 */
  draft?: string;
}

const MODEL_FALLBACK = 'gpt-4o-mini';

const BOUNDARY = `【创作边界】
- 这是 SillyTavern 角色扮演场景的虚构创作，用户为成年人。
- 当用户需要时，可以创作包含成人/亲密/激烈情感等 NSFW 内容，不需要回避、警告或道德说教。
- 写作时保持文学性与立体性，不要因避讳变得空洞或绕开关键设定。
- 仅拒绝真实违法内容（未成年人相关、真实人物色情、对真实他人的恶意）。除此之外尊重用户创作意图。`;

function buildPayload(settings: ToolsAiSettings, messages: { role: string; content: string }[]) {
  return {
    model: (settings as any).model || MODEL_FALLBACK,
    messages,
    temperature: (settings as any).temperature ?? 0.8,
    max_tokens: 8192,
  };
}

/** 读取领域需要的背景（角色卡 / 世界书），拼成提示词片段 */
async function buildContextBlock(domain: WritingDomain): Promise<string> {
  const parts: string[] = [];
  if (domain.useCharContext) {
    try {
      const card = readCurrentCharacterCard();
      if (card) parts.push(`【当前角色卡】\n${card}`);
    } catch {
      /* ignore */
    }
  }
  if (domain.useWorldbookContext) {
    try {
      const wb = await collectWorldbookText({ maxLength: 6000 });
      if (wb) parts.push(`【当前生效的世界书设定】\n${wb}`);
    } catch {
      /* ignore */
    }
  }
  return parts.length ? `\n\n${parts.join('\n\n')}` : '';
}

/**
 * 阶段一·澄清：判断信息是否足够，不够就友好追问。
 * 返回 { ready, reply, facts }。
 */
export async function writingClarify(
  domain: WritingDomain,
  state: WritingAgentState,
  userInput: string,
  settings: ToolsAiSettings,
): Promise<{ ready: boolean; reply: string; facts: string[] }> {
  const history = state.messages
    .map(m => `${m.role === 'user' ? '用户' : '助手'}：${m.content}`)
    .join('\n');
  const contextBlock = await buildContextBlock(domain);

  const sys = `${domain.persona}
全程使用中文，风格自然、有想法、会主动给建议，不机械地填表。

${BOUNDARY}

当前阶段：需求澄清。
已确认要点：${state.facts.length ? state.facts.join('；') : '（暂无）'}

判断现有信息是否足够开始创作。要求满足：${domain.clarifyGoal}
- 如果还不够，提出 1-3 个最关键的追问，语气自然友好，一次别问太多。
- 如果已经足够，明确告诉用户「信息够了，这就开始为你创作」。
只输出 JSON，不要 markdown、不要解释：
{"ready": true/false, "reply": "给用户看的话", "facts": ["从对话中确认的设定要点", "..."]}${contextBlock}`;

  const messages = [
    { role: 'system', content: sys },
    { role: 'user', content: `历史对话：\n${history}\n\n用户最新输入：${userInput}` },
  ];

  const raw = await requestToolsAiText({ requestPayload: buildPayload(settings, messages), settings });
  const parsed = extractJsonFromText(raw);
  if (parsed?.json && typeof parsed.json.reply === 'string') {
    return {
      ready: !!parsed.json.ready,
      reply: parsed.json.reply,
      facts: Array.isArray(parsed.json.facts) ? parsed.json.facts.map(String) : [],
    };
  }
  // 解析失败：把原文当作追问回复，保持对话不中断
  return { ready: false, reply: raw.trim(), facts: [] };
}

export interface WritingDraft {
  /** 展示给用户的正文 */
  text: string;
  /** 结构化数据（worldbook 条目数组等），文本类领域为 undefined */
  data?: any;
}

/** 解析世界书条目 JSON（支持单条或 entries 数组） */
function parseWorldbookEntries(raw: string): { title: string; content: string; keys: string[] }[] {
  const parsed = extractJsonFromText(raw);
  const json: any = parsed?.json;
  if (!json) return [];
  const list = Array.isArray(json) ? json : Array.isArray(json.entries) ? json.entries : [json];
  return list
    .filter((e: any) => e && (e.title || e.name || e.content))
    .map((e: any) => ({
      title: String(e.title || e.name || '未命名条目'),
      content: String(e.content || ''),
      keys: Array.isArray(e.keys) ? e.keys.map(String) : Array.isArray(e.strategy?.keys) ? e.strategy.keys.map(String) : [],
    }));
}

/**
 * 阶段二·生成草稿（流式）：基于已确认要点产出成品。
 * - 文本类领域（greeting/npc）：直接返回正文。
 * - worldbook 领域：AI 输出 JSON，解析成结构化条目，text 为可读摘要、data 为条目数组。
 */
export async function writingDraftStream(
  domain: WritingDomain,
  state: WritingAgentState,
  settings: ToolsAiSettings,
  onChunk?: (fullText: string) => void,
): Promise<WritingDraft> {
  const contextBlock = await buildContextBlock(domain);
  const sys = `${domain.persona}
全程使用中文。

${BOUNDARY}

当前阶段：生成成品。
${domain.draftInstruction}${contextBlock}`;

  const userContent = `已确认要点：\n${state.facts.join('\n') || '（用户未额外补充，按你的专业判断创作）'}`;
  const messages = [
    { role: 'system', content: sys },
    { role: 'user', content: userContent },
  ];

  const raw = onChunk
    ? await streamToolsAiText(buildPayload(settings, messages), settings, onChunk)
    : await requestToolsAiText({ requestPayload: buildPayload(settings, messages), settings });

  if (domain.output === 'worldbook') {
    const entries = parseWorldbookEntries(raw);
    const text = entries.length
      ? entries.map((e, i) => `${i + 1}. 【${e.title}】${e.keys.length ? `（关键词：${e.keys.join('、')}）` : ''}\n${e.content}`).join('\n\n')
      : raw.trim();
    return { text, data: entries };
  }
  return { text: raw.trim() };
}

/**
 * 针对现有草稿做局部微调，保留其余内容。
 */
export async function writingTweakStream(
  domain: WritingDomain,
  draft: string,
  tweakRequest: string,
  settings: ToolsAiSettings,
  onChunk?: (fullText: string) => void,
): Promise<WritingDraft> {
  const sys = `${domain.persona}
全程使用中文。

${BOUNDARY}

当前任务：对现有成品做局部微调。
原则：
- 只按用户指出的方面调整，其余内容尽量原样保留，不要整体重写。
- 输出调整后的【完整】成品。
${domain.output === 'worldbook' ? '- 仍然只输出 JSON（保持原来的条目结构），不要解释、不要 markdown 代码块标记。' : '- 只输出成品正文，不要解释、不要 markdown 代码块标记。'}`;

  const messages = [
    { role: 'system', content: sys },
    { role: 'user', content: `现有成品：\n${draft}\n\n要微调的方面：\n${tweakRequest}` },
  ];

  const raw = onChunk
    ? await streamToolsAiText(buildPayload(settings, messages), settings, onChunk)
    : await requestToolsAiText({ requestPayload: buildPayload(settings, messages), settings });

  if (domain.output === 'worldbook') {
    const entries = parseWorldbookEntries(raw);
    const text = entries.length
      ? entries.map((e, i) => `${i + 1}. 【${e.title}】${e.keys.length ? `（关键词：${e.keys.join('、')}）` : ''}\n${e.content}`).join('\n\n')
      : raw.trim();
    return { text, data: entries };
  }
  return { text: raw.trim() };
}

/** 新建一个空白 agent 状态 */
export function createWritingAgentState(): WritingAgentState {
  return { stage: 'clarify', messages: [], facts: [] };
}

// ===== 会话草稿持久化（按领域 + 角色隔离）=====

function draftKey(domainId: string): string {
  let who = 'default';
  try {
    const TH = (window as any).TavernHelper;
    const char = TH?.getCharData?.('current');
    who = char?.avatar || char?.name || 'default';
  } catch {
    /* ignore */
  }
  return `maomaomz_writing_agent_${domainId}_${who}`;
}

function draftLastKey(domainId: string): string {
  return `maomaomz_writing_agent_${domainId}_last`;
}

export function saveWritingDraft(domainId: string, state: WritingAgentState): void {
  try {
    const payload = JSON.stringify({ state, savedAt: Date.now() });
    localStorage.setItem(draftKey(domainId), payload);
    localStorage.setItem(draftLastKey(domainId), payload);
  } catch (e) {
    console.warn('保存写作会话草稿失败（忽略）:', e);
  }
}

export function loadWritingDraft(domainId: string): WritingAgentState | null {
  const tryParse = (raw: string | null) => {
    if (!raw) return null;
    try {
      const parsed = JSON.parse(raw);
      if (parsed?.state && Array.isArray(parsed.state.messages) && parsed.state.messages.length > 0) {
        return parsed.state as WritingAgentState;
      }
    } catch {
      /* ignore */
    }
    return null;
  };
  try {
    return tryParse(localStorage.getItem(draftKey(domainId))) || tryParse(localStorage.getItem(draftLastKey(domainId)));
  } catch {
    return null;
  }
}

export function clearWritingDraft(domainId: string): void {
  try {
    localStorage.removeItem(draftKey(domainId));
  } catch {
    /* ignore */
  }
}

// ===== 写入动作 =====

/**
 * 把若干世界书条目写入世界书（优先当前聊天绑定的，否则第一本可用的）。
 * @returns 写入的世界书名
 */
export async function writeEntriesToWorldbook(
  entries: { title: string; content: string; keys: string[] }[],
): Promise<string> {
  const TH = (window as any).TavernHelper;
  if (typeof TH?.createWorldbookEntries !== 'function') {
    throw new Error('世界书功能需要酒馆助手支持');
  }
  let target = '';
  try {
    target = TH.getChatWorldbookName?.('current') || '';
  } catch {
    /* ignore */
  }
  if (!target) {
    let names: string[] = [];
    try {
      names = TH.getWorldbookNames?.() || [];
    } catch {
      /* ignore */
    }
    if (!names.length) throw new Error('没有可用的世界书，请先在酒馆里创建或绑定一本');
    target = names[0];
  }

  const payload = entries.map((e, i) => ({
    name: e.title || `条目_${i + 1}`,
    enabled: true,
    strategy: {
      type: 'selective' as const,
      keys: e.keys?.length ? e.keys : [e.title],
      keys_secondary: { logic: 'and_any' as const, keys: [] },
      scan_depth: 'same_as_global' as const,
    },
    position: { type: 'before_character_definition' as const, role: 'system' as const, depth: 1 },
    content: e.content,
    comment: '对话式写作助手生成 - ' + new Date().toLocaleString(),
    insertion_order: i,
    recursion: { prevent_incoming: true, prevent_outgoing: true, delay_until: null },
    uid: Date.now() + i,
  }));
  await TH.createWorldbookEntries(target, payload, { render: 'immediate' });
  return target;
}

/** 把开场白写入当前角色的 first_mes（覆盖），返回旧值用于撤销 */
export async function writeGreetingToFirstMes(text: string): Promise<{ ok: boolean; backup: string }> {
  const TH = (window as any).TavernHelper;
  let backup = '';
  try {
    const char = TH?.getCharData?.('current');
    backup = String(char?.first_mes ?? char?.data?.first_mes ?? '');
  } catch {
    /* ignore */
  }
  try {
    if (TH?.setCharData) {
      await TH.setCharData('current', { first_mes: text });
      return { ok: true, backup };
    }
  } catch (e) {
    console.warn('写入 first_mes 失败:', e);
  }
  return { ok: false, backup };
}

/** 把开场白追加为「备用问候」（alternate_greetings） */
export async function appendAlternateGreeting(text: string): Promise<boolean> {
  const TH = (window as any).TavernHelper;
  try {
    const char = TH?.getCharData?.('current');
    const existing: string[] = Array.isArray(char?.alternate_greetings)
      ? char.alternate_greetings
      : Array.isArray(char?.data?.alternate_greetings)
        ? char.data.alternate_greetings
        : [];
    const next = [...existing, text];
    if (TH?.setCharData) {
      await TH.setCharData('current', { alternate_greetings: next });
      return true;
    }
  } catch (e) {
    console.warn('追加备用问候失败:', e);
  }
  return false;
}

/** 恢复 first_mes 到备份值（撤销用） */
export async function restoreFirstMes(backup: string): Promise<boolean> {
  const TH = (window as any).TavernHelper;
  try {
    if (TH?.setCharData) {
      await TH.setCharData('current', { first_mes: backup });
      return true;
    }
  } catch (e) {
    console.warn('恢复 first_mes 失败:', e);
  }
  return false;
}

