<template>
  <div style="font-family: -apple-system, BlinkMacSystemFont, 'PingFang SC', 'Microsoft YaHei', sans-serif">
    <!-- 说明 -->
    <div
      :style="{
        marginBottom: '14px',
        padding: '12px 14px',
        background: accentBg(0.12),
        border: '0.5px solid ' + accentBg(0.3),
        borderRadius: '12px',
      }"
    >
      <p :style="{ margin: '0 0 4px 0', color: domain.accent, fontSize: '13px' }">
        <i class="fa-solid fa-robot" style="margin-right: 6px"></i>{{ domain.title }}
      </p>
      <p style="margin: 0; color: #9ca3af; font-size: 11px; line-height: 1.6">{{ domain.intro }}</p>
    </div>

    <!-- 对话区 -->
    <div
      ref="chatBox"
      style="max-height: 380px; overflow-y: auto; padding: 4px; margin-bottom: 12px; display: flex; flex-direction: column; gap: 10px"
    >
      <div
        v-if="state.messages.length === 0"
        style="color: #6b7280; font-size: 13px; text-align: center; padding: 24px 0"
      >
        {{ domain.emptyHint }}
      </div>

      <div v-for="(msg, i) in state.messages" :key="i" :style="bubbleWrapStyle(msg.role)">
        <div :style="bubbleStyle(msg.role)">
          <div style="white-space: pre-wrap; word-break: break-word">{{ msg.content }}</div>

          <!-- 产物操作按钮 -->
          <div v-if="msg.artifact" style="margin-top: 10px; display: flex; gap: 8px; flex-wrap: wrap">
            <button :style="miniBtn('#0a84ff')" @click="copyText(msg.artifact.text)">
              <i class="fa-solid fa-copy"></i> 复制
            </button>

            <!-- 开场白：写入 first_mes / 加为备用 -->
            <template v-if="domain.output === 'greeting'">
              <button :style="miniBtn(domain.accent)" :disabled="busy" @click="applyGreeting(msg.artifact.text, 'first')">
                <i class="fa-solid fa-file-import"></i> 设为开场白
              </button>
              <button :style="miniBtn('#3a3a3a', '#ddd')" :disabled="busy" @click="applyGreeting(msg.artifact.text, 'alt')">
                <i class="fa-solid fa-plus"></i> 加为备用问候
              </button>
            </template>

            <!-- 世界书：批量写入 -->
            <template v-if="domain.output === 'worldbook' && msg.artifact.data?.length">
              <button :style="miniBtn('#667eea')" :disabled="busy" @click="applyWorldbook(msg.artifact.data)">
                <i class="fa-solid fa-book-medical"></i> 写入 {{ msg.artifact.data.length }} 条世界书
              </button>
            </template>

            <!-- NPC：写入世界书 -->
            <template v-if="domain.output === 'npc'">
              <button :style="miniBtn(domain.accent)" :disabled="busy" @click="applyNpc(msg.artifact.text)">
                <i class="fa-solid fa-book-medical"></i> 存入世界书
              </button>
            </template>

            <button :style="miniBtn('#3a3a3a', '#ddd')" :disabled="busy" @click="redoDraft">
              <i class="fa-solid fa-rotate"></i> 重做
            </button>

            <!-- 局部微调：只在最后一条产物上显示 -->
            <div
              v-if="i === lastDraftIndex"
              style="width: 100%; display: flex; gap: 6px; margin-top: 4px"
            >
              <input
                v-model="tweakInput"
                :disabled="busy"
                placeholder="想微调哪里？如：更简洁、换个氛围、补个细节…"
                style="flex: 1; padding: 7px 10px; background: rgba(30,41,59,0.6); border: 0.5px solid rgba(84,107,131,0.4); border-radius: 8px; color: #e8e8e8; font-size: 12px"
                @keydown.enter.prevent="tweakDraft"
              />
              <button :style="miniBtn(domain.accent)" :disabled="busy || !tweakInput.trim()" @click="tweakDraft">
                <i class="fa-solid fa-sliders"></i> 微调
              </button>
            </div>
          </div>
        </div>
      </div>

      <div v-if="busy" :style="bubbleWrapStyle('assistant')">
        <div :style="bubbleStyle('assistant')"><i class="fa-solid fa-spinner fa-spin"></i> {{ busyText }}</div>
      </div>
    </div>

    <!-- 输入区 -->
    <div style="display: flex; gap: 8px; align-items: flex-end">
      <textarea
        v-model="input"
        :disabled="busy"
        rows="2"
        :placeholder="domain.placeholder"
        style="flex: 1; resize: vertical; padding: 10px 12px; background: rgba(30,41,59,0.5); border: 0.5px solid rgba(84,107,131,0.4); border-radius: 10px; color: #e8e8e8; font-size: 13px; font-family: inherit"
        @keydown.enter.exact.prevent="send"
      ></textarea>
      <button :style="sendBtn" :disabled="busy || !input.trim()" @click="send">
        <i class="fa-solid fa-paper-plane"></i>
      </button>
    </div>

    <div style="margin-top: 10px; display: flex; gap: 8px">
      <button :style="miniBtn('#3a3a3a', '#ddd')" :disabled="busy" @click="resetAgent">
        <i class="fa-solid fa-broom"></i> 新建会话
      </button>
      <button v-if="canUndoGreeting" :style="miniBtn('#ff453a')" :disabled="busy" @click="undoGreeting">
        <i class="fa-solid fa-rotate-left"></i> 撤销设为开场白
      </button>
    </div>
  </div>
</template>

<script setup lang="ts">
import { storeToRefs } from 'pinia';
import { computed, nextTick, onMounted, reactive, ref } from 'vue';
import { useSettingsStore } from '../../settings';
import { copyToClipboard } from '../../utils';
import { translateError } from '../../utils/error-handler';
import {
  appendAlternateGreeting,
  clearWritingDraft,
  createWritingAgentState,
  loadWritingDraft,
  restoreFirstMes,
  saveWritingDraft,
  writeEntriesToWorldbook,
  writeGreetingToFirstMes,
  writingClarify,
  writingDraftStream,
  writingTweakStream,
  WRITING_DOMAINS,
  type WritingAgentState,
  type WritingDomain,
  type WritingMessage,
} from '../../utils/writing-agent';

const props = defineProps<{ domainId: string }>();

const domain: WritingDomain = WRITING_DOMAINS[props.domainId];

const settingsStore = useSettingsStore();
const { settings } = storeToRefs(settingsStore);

const state = reactive<WritingAgentState>(createWritingAgentState());
const input = ref('');
const busy = ref(false);
const busyText = ref('助手思考中…');
const chatBox = ref<HTMLElement | null>(null);
const tweakInput = ref('');

const aiSettings = () => settings.value as any;

const scrollToBottom = () => {
  nextTick(() => {
    if (chatBox.value) chatBox.value.scrollTop = chatBox.value.scrollHeight;
  });
};

const lastDraftIndex = computed(() => {
  for (let i = state.messages.length - 1; i >= 0; i--) {
    if (state.messages[i].artifact?.type === 'draft') return i;
  }
  return -1;
});

const persist = () => {
  if (state.messages.length > 0) saveWritingDraft(domain.id, state);
};

const pushMsg = (msg: WritingMessage) => {
  state.messages.push(msg);
  scrollToBottom();
  persist();
};

onMounted(() => {
  try {
    const draft = loadWritingDraft(domain.id);
    if (draft && draft.messages.length > 0) {
      Object.assign(state, draft);
      scrollToBottom();
    }
  } catch {
    /* ignore */
  }
});

const send = async () => {
  const text = input.value.trim();
  if (!text || busy.value) return;
  input.value = '';
  pushMsg({ role: 'user', content: text });

  busy.value = true;
  busyText.value = '助手思考中…';
  try {
    const result = await writingClarify(domain, state, text, aiSettings());
    for (const f of result.facts) {
      if (f && !state.facts.includes(f)) state.facts.push(f);
    }
    pushMsg({ role: 'assistant', content: result.reply });
    if (result.ready) {
      state.stage = 'draft';
      await runDraft();
    }
  } catch (e) {
    pushMsg({ role: 'assistant', content: '出错了：' + translateError(e, '思考') });
  } finally {
    busy.value = false;
  }
};

const runDraft = async () => {
  busy.value = true;
  busyText.value = '正在创作…';
  const idx = state.messages.length;
  state.messages.push({ role: 'assistant', content: '创作中…\n\n', artifact: { type: 'draft', text: '' } });
  scrollToBottom();
  try {
    const draft = await writingDraftStream(domain, state, aiSettings(), full => {
      const m = state.messages[idx];
      if (m && domain.output !== 'worldbook') {
        m.content = '成品来啦：\n\n' + full;
        if (m.artifact) m.artifact.text = full;
        scrollToBottom();
      }
    });
    state.draft = draft.text;
    state.stage = 'done';
    const m = state.messages[idx];
    if (m) {
      m.content = '成品来啦：\n\n' + draft.text;
      if (m.artifact) {
        m.artifact.text = draft.text;
        m.artifact.data = draft.data;
      }
    }
    persist();
  } catch (e) {
    const m = state.messages[idx];
    if (m) m.content = '创作出错：' + translateError(e, '创作');
    persist();
  } finally {
    busy.value = false;
  }
};

const redoDraft = async () => {
  if (busy.value) return;
  await runDraft();
};

const tweakDraft = async () => {
  const req = tweakInput.value.trim();
  if (!req || busy.value || !state.draft) return;
  tweakInput.value = '';
  pushMsg({ role: 'user', content: '微调：' + req });
  busy.value = true;
  busyText.value = '正在微调…';
  const idx = state.messages.length;
  state.messages.push({ role: 'assistant', content: '微调中…\n\n', artifact: { type: 'draft', text: '' } });
  scrollToBottom();
  try {
    const draft = await writingTweakStream(domain, state.draft, req, aiSettings(), full => {
      const m = state.messages[idx];
      if (m && domain.output !== 'worldbook') {
        m.content = '微调后：\n\n' + full;
        if (m.artifact) m.artifact.text = full;
        scrollToBottom();
      }
    });
    state.draft = draft.text;
    const m = state.messages[idx];
    if (m) {
      m.content = '微调后：\n\n' + draft.text;
      if (m.artifact) {
        m.artifact.text = draft.text;
        m.artifact.data = draft.data;
      }
    }
    persist();
  } catch (e) {
    const m = state.messages[idx];
    if (m) m.content = '微调出错：' + translateError(e, '微调');
    persist();
  } finally {
    busy.value = false;
  }
};

const copyText = async (text: string) => {
  await copyToClipboard(text, '已复制到剪贴板');
};

// ===== 写入动作 =====
const greetingBackup = ref<string | null>(null);
const canUndoGreeting = ref(false);

const applyGreeting = async (text: string, target: 'first' | 'alt') => {
  if (busy.value) return;
  busy.value = true;
  busyText.value = target === 'first' ? '正在设为开场白…' : '正在加为备用问候…';
  try {
    if (target === 'first') {
      const res = await writeGreetingToFirstMes(text);
      if (res.ok) {
        greetingBackup.value = res.backup;
        canUndoGreeting.value = true;
        window.toastr.success('已设为开场白（first_mes），写错了可点下方撤销');
      } else {
        window.toastr.error('写入失败：未找到当前角色或接口不可用');
      }
    } else {
      const ok = await appendAlternateGreeting(text);
      if (ok) window.toastr.success('已加为备用问候（alternate greeting）');
      else window.toastr.error('追加失败：未找到当前角色或接口不可用');
    }
  } catch (e) {
    window.toastr.error(translateError(e, '写入开场白'));
  } finally {
    busy.value = false;
  }
};

const undoGreeting = async () => {
  if (busy.value || greetingBackup.value === null) return;
  busy.value = true;
  busyText.value = '正在撤销…';
  try {
    const ok = await restoreFirstMes(greetingBackup.value);
    if (ok) {
      canUndoGreeting.value = false;
      greetingBackup.value = null;
      window.toastr.success('已撤销，开场白恢复成写入前的内容');
    } else {
      window.toastr.error('撤销失败');
    }
  } catch (e) {
    window.toastr.error(translateError(e, '撤销'));
  } finally {
    busy.value = false;
  }
};

const applyWorldbook = async (entries: { title: string; content: string; keys: string[] }[]) => {
  if (busy.value) return;
  busy.value = true;
  busyText.value = '正在写入世界书…';
  try {
    const wb = await writeEntriesToWorldbook(entries);
    window.toastr.success(`已写入 ${entries.length} 条世界书到「${wb}」`);
  } catch (e) {
    window.toastr.error(translateError(e, '写入世界书'));
  } finally {
    busy.value = false;
  }
};

const applyNpc = async (text: string) => {
  if (busy.value) return;
  busy.value = true;
  busyText.value = '正在存入世界书…';
  try {
    // 从 NPC 正文里抽名字作为条目名/关键词
    const nameMatch = text.match(/【姓名】\s*(.+)/);
    const name = nameMatch ? nameMatch[1].trim().split(/\s/)[0] : 'NPC';
    const wb = await writeEntriesToWorldbook([{ title: name, content: text, keys: [name] }]);
    window.toastr.success(`已把「${name}」存入世界书「${wb}」`);
  } catch (e) {
    window.toastr.error(translateError(e, '存入世界书'));
  } finally {
    busy.value = false;
  }
};

const resetAgent = () => {
  if (busy.value) return;
  state.stage = 'clarify';
  state.messages = [];
  state.facts = [];
  state.draft = undefined;
  input.value = '';
  tweakInput.value = '';
  greetingBackup.value = null;
  canUndoGreeting.value = false;
  clearWritingDraft(domain.id);
};

// ===== 样式 =====
const accentBg = (alpha: number) => {
  const hex = domain.accent.replace('#', '');
  const r = parseInt(hex.slice(0, 2), 16);
  const g = parseInt(hex.slice(2, 4), 16);
  const b = parseInt(hex.slice(4, 6), 16);
  return `rgba(${r}, ${g}, ${b}, ${alpha})`;
};

const bubbleWrapStyle = (role: string) => ({
  display: 'flex',
  justifyContent: role === 'user' ? 'flex-end' : 'flex-start',
});

const bubbleStyle = (role: string) => ({
  maxWidth: '85%',
  padding: '10px 13px',
  borderRadius: '14px',
  fontSize: '13px',
  lineHeight: '1.6',
  background: role === 'user' ? 'rgba(10,132,255,0.85)' : 'rgba(44,44,46,0.9)',
  color: role === 'user' ? '#fff' : '#e8e8e8',
  border: role === 'user' ? 'none' : '0.5px solid rgba(255,255,255,0.08)',
});

const miniBtn = (bg: string, color = '#fff') => ({
  padding: '6px 12px',
  background: bg,
  border: 'none',
  borderRadius: '8px',
  color,
  cursor: 'pointer',
  fontSize: '12px',
  fontWeight: 600,
});

const sendBtn = {
  padding: '10px 16px',
  background: domain.accent,
  border: 'none',
  borderRadius: '10px',
  color: '#fff',
  cursor: 'pointer',
  fontSize: '14px',
  height: 'fit-content',
};
</script>
